glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
float noise(vec2 p){ vec2 i=floor(p); vec2 f=fract(p); vec2 u=f*f*(3.0-2.0*f); return mix(mix(hash(i), hash(i+vec2(1.0,0.0)), u.x), mix(hash(i+vec2(0.0,1.0)), hash(i+vec2(1.0,1.0)), u.x), u.y); }
void main(){
 vec2 p = vUv;
 float n = noise(p * 46.0) * 0.055 + noise(p * 11.0) * 0.035;
 vec3 cream = vec3(0.918, 0.820, 0.650);
 vec3 ochre = vec3(0.835, 0.590, 0.235);
 float wash = smoothstep(0.0, 1.0, p.y) * 0.22 + n;
 vec3 col = mix(cream, ochre, wash);
 float edge = smoothstep(0.0, 0.08, p.x) * smoothstep(0.0, 0.08, p.y) * smoothstep(0.0, 0.08, 1.0-p.x) * smoothstep(0.0, 0.08, 1.0-p.y);
 gl_FragColor = vec4(col * (0.92 + 0.08 * edge), 1.0);
}
